#include "tmp117.h"
#include <Wire.h>
#include <SparkFun_TMP117.h>
static TMP117 sensor;
static float _t=0;static unsigned long _l=0;
void tmp117_setup(){Wire.begin();if(!sensor.begin()){Serial.println("[tmp117] Fail!");return;}Serial.println("[tmp117] OK ±0.1C");}
void tmp117_loop(){if(millis()-_l<1000)return;_l=millis();if(sensor.dataReady())_t=sensor.readTempC();}
float tmp117_get_temperature(){return _t;}
